        count1 += totalPairs - sameVertexPairs;
    }

    let parallelogramCount = 0;
    for (let i = 0; i < n; i++) {
        const A = points[i];
        const vectors: [number, number][] = [];
        for (let j = 0; j < n; j++) {
            if (j === i) continue;
            const B = points[j];
            const dx = B[0] - A[0];
            const dy = B[1] - A[1];
            vectors.push([dx, dy]);
        }

        const m = vectors.length;
        for (let j = 0; j < m; j++) {
            for (let k = j + 1; k < m; k++) {
