                const ny = dy / g;
                slopeKey = `${nx},${ny}`;
                interceptKey = `${(y1 * dx - x1 * dy)}/${dx}`;
            }
            const segRep = `${i},${j}`;

            if (!slopeGroups.has(slopeKey)) {
                slopeGroups.set(slopeKey, new Map());
            }
            const interceptMap = slopeGroups.get(slopeKey);
            if (!interceptMap.has(interceptKey)) {
                interceptMap.set(interceptKey, new Set());
            }
            interceptMap.get(interceptKey).add(segRep);
        }
    }

    let totalParallelCount = 0;
    for (const interceptMap of slopeGroups.values()) {
        const groups = Array.from(interceptMap.values());
        const groupCount = groups.length;
        for (let i = 0; i < groupCount; i++) {
