            for (let j = i + 1; j < groupCount; j++) {
                const set2 = groups[j];
                totalParallelCount += set1.size * set2.size;
            }
        }
    }

    let parallelogramCount = 0;
    if (pointSet.size === n) {
        for (let i = 0; i < n; i++) {
