                    if (pointSet.has(d1Str) && D1[0] !== A[0] || D1[1] !== A[1] && D1[0] !== B[0] || D1[1] !== B[1] && D1[0] !== C[0] || D1[1] !== C[1]) {
                        parallelogramCount++;
