                    if (pointSet.has(d2Str) && D2[0] !== A[0] || D2[1] !== A[1] && D2[0] !== B[0] || D2[1] !== B[1] && D2[0] !== C[0] || D2[1] !== C[1]) {
                        parallelogramCount++;
